`,xt(t.p,{children:xt(t.img,{src:"./pic/basic-data-info.jpg",alt:""})}),`
`,xt(t.p,{children:[xt(t.strong,{children:"Data distribution statistics for Garments2Look."})," The real and synthetic data in the final dataset are maintained at ∼1:1 ratio. We collect data covering diverse genders, different numbers of garment images per outfit, different layering order lengths, and encompassing a broad range of garments categories and outfit combination patterns. We also pay attention to textual annotation to facilitate future multimodal research."]})]})}function See(e={}){const{wrapper:t}=e.components||{};return t?xt(t,{...e,children:xt(n0,{...e})}):n0(e)}function a0(e){const t={h1:"h1",img:"img",p:"p",strong:"strong",...e.components};return xt(Ne,{children:[xt(t.h1,{children:"Results"}),`
